import { describe, expect, it } from '@a0n/gnosis/test';
import { QDoc } from './crdt/qdoc';
import {
  appendCertifiedAppEnvelopeAttestation,
  auditCertifiedAppEnvelope,
  createCertifiedAppEnvelopeFromGgSource,
  loadCertifiedAppEnvelopeByAliasFromQDoc,
  loadCertifiedAppEnvelopeFromQDoc,
  serializeCertifiedAppEnvelopeMirror,
  storeCertifiedAppEnvelopeInQDoc,
} from './certified-app';
import { evaluateAgentSwarmContract } from './runtime/agent-swarm-contract';

const SIMPLE_GG = [
  "(input:Source)-[:PROCESS { fn: 'identity' }]->(output:Sink)",
].join('\n');

function createMergeReadyAgentSwarmCertificate() {
  return evaluateAgentSwarmContract({
    changeId: 'pr-481',
    targetBranch: 'main',
    protectedBranch: true,
    riskLevel: 'standard',
    taskContracts: [
      {
        id: 'certified-app',
        title: 'Add certified-app attestation support',
        owner: 'gnosis',
        allowedPathScopes: ['open-source/gnosis/src/certified-app.ts'],
        allowedTools: ['apply_patch', 'pnpm:test'],
        requiredVerifications: ['gnosis:test'],
        allowPathOverlapWith: [],
        requiresTrace: true,
        requiresHumanReview: false,
      },
    ],
    taskExecutions: [
      {
        taskId: 'certified-app',
        agentId: 'agent-1',
        status: 'completed',
        touchedPaths: ['open-source/gnosis/src/certified-app.ts'],
        toolsUsed: ['apply_patch', 'pnpm:test'],
        traceId: 'trace-1',
        traceDigest: 'trace-digest-1',
        verificationResults: [{ id: 'gnosis:test', status: 'passed' }],
        startedAt: '2026-04-10T12:00:00.000Z',
        finishedAt: '2026-04-10T12:01:00.000Z',
      },
    ],
    approvals: [
      {
        reviewerId: 'reviewer-human-1',
        reviewerType: 'human',
        approved: true,
        role: 'maintainer',
      },
    ],
    reviewPolicy: {
      minimumApprovals: 1,
      minimumHumanApprovals: 1,
      requireHumanOnProtectedBranch: true,
    },
    globalVerification: {
      requiredChecks: ['gnosis:test'],
    },
  });
}

describe('certified-app envelope', () => {
  it('produces a stable digest for identical certified sources', () => {
    const first = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });
    const second = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
      createdAt: first.createdAt,
    });

    expect(first.envelopeId).toBe(second.envelopeId);
    expect(first.digest).toBe(second.digest);
    expect(first.core.universeDigest).toBe(
      first.core.universeCertificate.digest
    );
  });

  it('fails audit on tampered source digest and runtime target mismatch', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });

    const tampered = {
      ...envelope,
      core: {
        ...envelope.core,
        sourceDigest: 'tampered-source',
        capabilitySummary: {
          ...envelope.core.capabilitySummary,
          target: 'workers',
        },
      },
    };
    const audit = auditCertifiedAppEnvelope(tampered);

    expect(audit.selfConsistent).toBe(false);
    expect(audit.issues.some((issue) => issue.includes('Source digest'))).toBe(
      true
    );
    expect(
      audit.issues.some((issue) => issue.includes('Capability target'))
    ).toBe(true);
  });

  it('fails audit on runtime host mismatch and publish identity contradictions', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });

    const withRuntime = appendCertifiedAppEnvelopeAttestation(envelope, {
      kind: 'runtime_start',
      attestedAt: new Date(
        Date.parse(envelope.createdAt) + 1_000
      ).toISOString(),
      runtimeName: 'demo-runtime',
      hostTarget: 'bun',
      pid: '123',
      port: 7331,
      healthUrl: 'http://127.0.0.1:7331/health',
    });
    const withPublish = appendCertifiedAppEnvelopeAttestation(withRuntime, {
      kind: 'publish_proof',
      attestedAt: new Date(
        Date.parse(envelope.createdAt) + 2_000
      ).toISOString(),
      manifestPath: 'public/content/publish-proof.json',
      proofMode: 'anchor',
      app: 'demo-app',
      site: 'demo-site',
      domain: 'demo.local',
      tokenId: '42',
    });
    const audit = auditCertifiedAppEnvelope(
      appendCertifiedAppEnvelopeAttestation(withPublish, {
        kind: 'aeonpid_registration',
        attestedAt: new Date(
          Date.parse(envelope.createdAt) + 3_000
        ).toISOString(),
        directoryId: 'dir-1',
        app: 'demo-app',
        site: 'different-site',
        domain: 'other.local',
        tokenId: '43',
        proofMode: 'snapshot',
      })
    );

    expect(audit.selfConsistent).toBe(false);
    expect(
      audit.issues.some((issue) => issue.includes('Runtime start host target'))
    ).toBe(true);
    expect(
      audit.issues.some((issue) => issue.includes('AeonPID registration site'))
    ).toBe(true);
    expect(
      audit.issues.some((issue) =>
        issue.includes('AeonPID registration domain')
      )
    ).toBe(true);
    expect(audit.issues.some((issue) => issue.includes('token id'))).toBe(true);
    expect(audit.issues.some((issue) => issue.includes('proof mode'))).toBe(
      true
    );
  });

  it('carries a merge-ready agent swarm adjudication attestation and round-trips through QDoc', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });
    const adjudication = createMergeReadyAgentSwarmCertificate();
    const attestation = {
      kind: 'agent_swarm_adjudication' as const,
      attestedAt: new Date(adjudication.certificate.generatedAt).toISOString(),
      certificate: adjudication.certificate,
      summary: {
        certificateDigest: adjudication.certificate.digest,
        changeId: adjudication.certificate.changeId,
        targetBranch: adjudication.certificate.targetBranch,
        protectedBranch: adjudication.certificate.protectedBranch,
        riskLevel: adjudication.certificate.riskLevel,
        decision: adjudication.certificate.decision,
        issueCount: adjudication.certificate.issues.length,
        errorCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'error'
        ).length,
        warningCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'warning'
        ).length,
        infoCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'info'
        ).length,
        taskCount: adjudication.certificate.metrics.taskCount,
        executionCount: adjudication.certificate.metrics.executionCount,
        approvalCount: adjudication.certificate.metrics.approvalCount,
        humanApprovalCount: adjudication.certificate.metrics.humanApprovalCount,
      },
    } as const;

    const withAttestation = appendCertifiedAppEnvelopeAttestation(
      envelope,
      attestation
    );
    const doc = new QDoc({ guid: 'certified-app-agent-swarm-test' });
    storeCertifiedAppEnvelopeInQDoc(doc, withAttestation, ['agent-swarm']);

    expect(
      loadCertifiedAppEnvelopeByAliasFromQDoc(
        doc,
        'agent-swarm'
      )?.attestations.at(-1)?.kind
    ).toBe('agent_swarm_adjudication');
    expect(auditCertifiedAppEnvelope(withAttestation).selfConsistent).toBe(
      true
    );
  });

  it('allows swarm adjudication attestations to be appended after the merge certificate was generated', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });
    const adjudication = createMergeReadyAgentSwarmCertificate();

    const withAttestation = appendCertifiedAppEnvelopeAttestation(envelope, {
      kind: 'agent_swarm_adjudication',
      attestedAt: new Date(
        Math.max(
          Date.parse(envelope.createdAt) + 1_000,
          adjudication.certificate.generatedAt + 1_000
        )
      ).toISOString(),
      certificate: adjudication.certificate,
      summary: {
        certificateDigest: adjudication.certificate.digest,
        changeId: adjudication.certificate.changeId,
        targetBranch: adjudication.certificate.targetBranch,
        protectedBranch: adjudication.certificate.protectedBranch,
        riskLevel: adjudication.certificate.riskLevel,
        decision: adjudication.certificate.decision,
        issueCount: adjudication.certificate.issues.length,
        errorCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'error'
        ).length,
        warningCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'warning'
        ).length,
        infoCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'info'
        ).length,
        taskCount: adjudication.certificate.metrics.taskCount,
        executionCount: adjudication.certificate.metrics.executionCount,
        approvalCount: adjudication.certificate.metrics.approvalCount,
        humanApprovalCount: adjudication.certificate.metrics.humanApprovalCount,
      },
    });

    expect(auditCertifiedAppEnvelope(withAttestation).selfConsistent).toBe(
      true
    );
  });

  it('fails audit when agent swarm summary diverges from the certificate', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });
    const adjudication = createMergeReadyAgentSwarmCertificate();
    const withAttestation = appendCertifiedAppEnvelopeAttestation(envelope, {
      kind: 'agent_swarm_adjudication',
      attestedAt: new Date(adjudication.certificate.generatedAt).toISOString(),
      certificate: adjudication.certificate,
      summary: {
        certificateDigest: adjudication.certificate.digest,
        changeId: adjudication.certificate.changeId,
        targetBranch: adjudication.certificate.targetBranch,
        protectedBranch: adjudication.certificate.protectedBranch,
        riskLevel: adjudication.certificate.riskLevel,
        decision: adjudication.certificate.decision,
        issueCount: adjudication.certificate.issues.length,
        errorCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'error'
        ).length,
        warningCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'warning'
        ).length,
        infoCount: adjudication.certificate.issues.filter(
          (issue) => issue.severity === 'info'
        ).length,
        taskCount: adjudication.certificate.metrics.taskCount,
        executionCount: adjudication.certificate.metrics.executionCount,
        approvalCount: adjudication.certificate.metrics.approvalCount,
        humanApprovalCount: adjudication.certificate.metrics.humanApprovalCount,
      },
    });

    const tampered = {
      ...withAttestation,
      attestations: withAttestation.attestations.map((attestation, index) =>
        index === withAttestation.attestations.length - 1 &&
        attestation.kind === 'agent_swarm_adjudication'
          ? {
              ...attestation,
              summary: {
                ...attestation.summary,
                issueCount: attestation.summary.issueCount + 1,
              },
            }
          : attestation
      ),
    };
    const audit = auditCertifiedAppEnvelope(tampered);

    expect(audit.selfConsistent).toBe(false);
    expect(
      audit.issues.some((issue) =>
        issue.includes('Agent swarm adjudication summary')
      )
    ).toBe(true);
  });

  it('round-trips through QDoc storage with aliases', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });
    const doc = new QDoc({ guid: 'certified-app-test' });

    storeCertifiedAppEnvelopeInQDoc(doc, envelope, ['artifact-1']);

    expect(
      loadCertifiedAppEnvelopeFromQDoc(doc, envelope.envelopeId)?.digest
    ).toBe(envelope.digest);
    expect(
      loadCertifiedAppEnvelopeByAliasFromQDoc(doc, 'artifact-1')?.digest
    ).toBe(envelope.digest);
    expect(loadCertifiedAppEnvelopeByAliasFromQDoc(doc)?.digest).toBe(
      envelope.digest
    );
  });

  it('serializes a deterministic JSON mirror', () => {
    const envelope = createCertifiedAppEnvelopeFromGgSource({
      appId: 'demo-app',
      sourcePath: 'apps/demo-app',
      entrypoint: 'main.gg',
      artifactId: 'artifact-1',
      artifactFingerprint: 'artifact-1',
      runtimeTarget: 'gnode',
      ggSource: SIMPLE_GG,
    });

    const first = serializeCertifiedAppEnvelopeMirror(envelope);
    const second = serializeCertifiedAppEnvelopeMirror(envelope);
    const parsed = JSON.parse(first) as { envelopeId: string; digest: string };

    expect(first).toBe(second);
    expect(parsed.envelopeId).toBe(envelope.envelopeId);
    expect(parsed.digest).toBe(envelope.digest);
  });
});
